package testservices

import (
	"testing"

	"github.com/bsv-blockchain/go-sdk/transaction"
	"github.com/stretchr/testify/require"
)

type MinedTransactionFixture interface {
	Tx() *transaction.Transaction
	TxID() string
	RawTx() string
	WillReturnRawTx()
	WillReturnMerklePath()
}

type minedTransactionFixture struct {
	testing.TB

	woc                   WhatsOnChainFixture
	beefHex               string
	merklePathWoCResponse string
	blockHash             string
	blockWoCResponse      string
}

func (f *minedTransactionFixture) Tx() *transaction.Transaction {
	tx, err := transaction.NewTransactionFromBEEFHex(f.beefHex)
	require.NoError(f, err)

	return tx
}

func (f *minedTransactionFixture) TxID() string {
	tx := f.Tx()
	return tx.TxID().String()
}

func (f *minedTransactionFixture) RawTx() string {
	tx := f.Tx()
	return tx.Hex()
}

func (f *minedTransactionFixture) WillReturnRawTx() {
	txID := f.TxID()
	rawTx := f.RawTx()
	f.woc.WillRespondWithRawTx(200, txID, rawTx, nil)
}

func (f *minedTransactionFixture) WillReturnMerklePath() {
	txID := f.TxID()
	f.woc.WillRespondWithMerklePath(200, txID, f.merklePathWoCResponse)
	f.woc.WillRespondWithBlockHeader(200, f.blockHash, f.blockWoCResponse)
}

